head.script:
 		  /**
		 * 화면 초기화에 필요한 로직을 수행한다.
		 * @param
		 * @return
		 */
		scwin.initScreen = function() {

			/**
			 *  Drag & Drop 이벤트 처리용 함수호출
			 * @param
			 * @return
			 */
			var singlFiledragdom = _ibxAtchFile.render;                                          // 첨부파일 정보가 보여질 그리드ID 
			singlFiledragdom.addEventListener("dragover", scwin.fileDragHandler, false);
	    	singlFiledragdom.addEventListener("dragenter", scwin.fileDragHandler, false);  // for ie
			singlFiledragdom.addEventListener("dragleave", scwin.fileDragHandler, false);
			singlFiledragdom.addEventListener("drop", scwin.singlFileDropHandler, false);

			/*********************** Drag & Drop 끝 ***********************/

		};
        /**
         * 첨부파일 선택이후 콜백
         * @param
         * @return
         */
        scwin._singlSelectCallback = function() {
        	fileLib.selectCallback(_mpdSinglFile, _ibxAtchFile, _dltSinglFile); 
        	var fileInfos = _mpdSinglFile.getFileInfos();
        	//_ibxAtchFile.setValue(fileInfos[0].name);
        };

        /**
         * 등록하고자 선택된 첨부파일 삭제처리(단, 저장전에만 가능함)
         * @param
         * @return
         */
        scwin._btnDelSinglFile_onclick = function() {
        	var existYn = _ibxAtchFile.getValue();
        	if (existYn != null && ( _mpdSinglFile.getFileCount() > 0 || _dltSinglFile.getTotalRow() > 0)) {
        		scwin.deleteConfirmCallback();
        		//comLib.confirm($p, utilLib.getMessage("SCM.INFO.00339"), "scwin.deleteConfirmCallback");
        		//comLib.confirm($p, ["삭제하시겠습니까?<br/>(저장을 하셔야 실제 삭제처리가됩니다.)","info"], "scwin.deleteConfirmCallback");
        	}
		};

		scwin.deleteConfirmCallback = function() {
			_ibxAtchFile.setValue("");
			_mpdSinglFile.removeAllFiles();
			_dltSinglFile.removeAll();
		};



        /**
         * 첨부 파일 임시저장후 콜백(전송)
         * @param
         * @return
         */
		scwin._mpdSinglFile_ondone = function(data) {
			//첨부파일정보 셋팅
			var rtnYn = fileLib.dataListSetting(_dltSinglFile, data);
			if (rtnYn) {
				// comLib.confirm($p.parent().$p, utilLib.getMessage("SCM.INFO.00321"), "scwin.saveFaxConfirmCallback");
				$p.parent().scwin.saveFaxConfirmCallback();
			}
		};

		/**
		 * 화면단 프로그래스바를 사용할 경우 사용
		 * @param info 서버로 업로드시 파일전송 상태값
		 * @return
		 */
		scwin._mpdSinglFile_onprogress = function(info) {
			_ibxBigFileStatus.setValue( info.percentData + "%" );
			_ibxBigFileStatus.setStyle("display", "block");
			_ibxBigFileStatus.setStyle("background","#ffcc00");
			_ibxBigFileStatus.setStyle("background-repeat","repeat-x");
			_ibxBigFileStatus.setStyle("background-position","left top");
			_ibxBigFileStatus.setStyle("background-image","url('/resources/images/common/pro.png')");
			_ibxBigFileStatus.setStyle( "width" , info.percentData + "%" );
		};        


		scwin._mpdSinglFile_onerror = function(data) {
			comLib.alert($p, data.message );
		};

		/**
		 * 임시저장 함수 호출
		 * @param
		 * @return
		 */
		scwin.fileStartUpload = function() {
			_mpdSinglFile.startUpload();
		};

		/**
		 * 품 초기화
		 * @param
		 * @return
		 */
		scwin._atchflFormReset = function() {
			_dltSinglFile.setJSON([]);
			_mpdSinglFile.removeAllFiles();
			_ibxAtchFile.setValue("");
			_ibxBigFileStatus.setValue( "" );
			_ibxBigFileStatus.setStyle("background-image","");
			_ibxBigFileStatus.setStyle("background","#ffffff");
			_ibxBigFileStatus.setStyle( "width" , "0%" );
		};


		/*********************** Drag & Drop 시작 ***********************/
		/**
		 * drop할때 발생하는 이벤트
		 * @param
		 * @return
		 */
		 /*
		_ibxAtchFile._handleOndrop = function(e) {
		    try {
		        $W._c.stopEvent(e);

		        var _6c = e.dataTransfer.files;

		         for (var i = 0; i < _6c.length; i++) {
		                if ($.inArray(_6c[i].name, this.getValue()) == -1) {
		                    this.fileArray.push(_6c[i]);
		                    //this.fileNameArr.push(_6c[i].name);
		                    this.setValue(_6c[i].name);
		                    this._inx++;
		                } else {
		                    comLib.alert($p, "파일이 이미 있습니다.  (" + _6c[i].name + ")");
		                }
		            }
		      } catch (e) {
		      	$W.exception.printStackTrace(e, null, this);
		      }
		};
		*/
		/**
		 *  file drag
		 * @param  event
		 * @return 
		 */
		scwin.fileDragHandler = function(e){
			WebSquare.event.stopEvent(e);
			//e.target.className = (e.type == "dragover" ? "hover" : "");
		}

		/**
		 * file drop
		 * @param
		 * @return
		 */
		scwin.singlFileDropHandler = function(e){
			scwin.fileDragHandler(e);
			_mpdSinglFile._handleOndrop(e);				//멀티컨포넌트 ID로 셋팅
			scwin._singlSelectCallback();
		}
